import React from 'react';
import { useData } from '../../context/DataContext';
import { formatDate } from '../../utils/helpers';

const Reports = () => {
  const { attendanceLogs, facilityLogs, tasks, staffList } = useData();

  // Danh sách các trạng thái được coi là BÌNH THƯỜNG
  const GOOD_STATUSES = ['Mát', 'Tốt', 'Sạch & Tốt', 'Ổn định', 'Còn pin', 'Xanh tốt'];

  // Lọc ra các log có vấn đề (Status không nằm trong danh sách tốt)
  const issueLogs = facilityLogs.filter(log => !GOOD_STATUSES.includes(log.status));

  return (
    <div>
      <h2>Báo cáo tổng hợp</h2>
      
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        
        {/* Cột 1: Lịch sử Điểm danh */}
        <div>
          <h3>Lịch sử Điểm danh</h3>
          <ul style={{ maxHeight: '300px', overflowY: 'auto', border: '1px solid #ddd', padding: '10px', background: '#fff' }}>
            {attendanceLogs.length === 0 && <p style={{ padding: '10px' }}>Chưa có dữ liệu</p>}
            {attendanceLogs.map((log, index) => (
              <li key={index} style={{ marginBottom: '8px', borderBottom: '1px solid #eee', paddingBottom: '5px' }}>
                <strong>{log.staffName}</strong>: <span style={{ color: log.type === 'Check-in' ? 'green' : 'orange', fontWeight: 'bold' }}>{log.type}</span> lúc {formatDate(log.time)}
              </li>
            ))}
          </ul>
        </div>

        {/* Cột 2: Báo cáo CSVC */}
        <div>
          <h3>Báo cáo CSVC (Bất thường)</h3>
          <ul style={{ maxHeight: '300px', overflowY: 'auto', border: '1px solid #ddd', padding: '10px', background: '#fff' }}>
            {issueLogs.length === 0 ? (
              <p style={{ padding: '10px', color: 'green', fontWeight: 'bold' }}>Hệ thống CSVC & Cây xanh ổn định</p>
            ) : (
              issueLogs.map((log, index) => (
                <li key={index} style={{ color: '#d9534f', marginBottom: '8px', borderBottom: '1px solid #eee', paddingBottom: '5px' }}>
                  <strong>[{log.area || 'Chưa rõ'}] {log.item}</strong>: {log.status}
                  <br/>
                  <span style={{ fontSize: '0.9rem', color: '#555' }}>
                     Báo cáo bởi {log.staffName} ({log.type} - {formatDate(log.time)})
                  </span>
                </li>
              ))
            )}
          </ul>
        </div>
        
        {/* Phần 3: Báo cáo tiến độ & Giải trình */}
        <div style={{ gridColumn: 'span 2', marginTop: '20px' }}>
          <h3>Báo cáo tiến độ công việc & Giải trình</h3>
          <div style={{ overflowX: 'auto' }}>
            <table border="1" style={{ width: '100%', borderCollapse: 'collapse', background: 'white' }}>
              <thead style={{ background: '#f5f5f5' }}>
                <tr>
                  <th style={{ padding: '10px' }}>Nhân sự</th>
                  <th style={{ padding: '10px' }}>Công việc</th>
                  <th style={{ padding: '10px' }}>Hạn chót</th>
                  <th style={{ padding: '10px' }}>Tiến độ</th>
                  <th style={{ padding: '10px' }}>Lý do (nếu &lt; 90%)</th>
                  <th style={{ padding: '10px' }}>Kỷ luật (Dự kiến)</th>
                </tr>
              </thead>
              <tbody>
                {tasks.length === 0 ? (
                   <tr><td colSpan="6" style={{ textAlign: 'center', padding: '10px' }}>Chưa có công việc nào</td></tr>
                ) : (
                  tasks.map(task => {
                    const staff = staffList.find(s => s.id === task.assigneeId);
                    const isOverdue = task.deadline && new Date() > new Date(task.deadline) && task.progress < 100;
                    
                    return (
                      <tr key={task.id}>
                        <td style={{ padding: '10px' }}>{staff?.name}</td>
                        <td style={{ padding: '10px' }}>{task.title}</td>
                        <td style={{ padding: '10px' }}>
                           {task.deadline ? new Date(task.deadline).toLocaleString('vi-VN') : 'N/A'}
                           {isOverdue && <div style={{ color: 'red', fontWeight: 'bold', marginTop: '5px' }}>⚠️ (Quá hạn)</div>}
                        </td>
                        <td style={{ padding: '10px', textAlign: 'center', fontWeight: 'bold', color: task.progress < 100 ? 'orange' : 'green' }}>
                          {task.progress}%
                        </td>
                        <td style={{ padding: '10px', color: '#555', fontStyle: 'italic' }}>
                          {task.progress < 90 ? (task.reason || 'Chưa có giải trình') : 'N/A'}
                        </td>
                        <td style={{ padding: '10px', color: '#d9534f', fontWeight: 'bold' }}>
                          {task.penalty || 'Không'}
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Reports;
